import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting", () => {
    it.todo("should calculate premium for a single sword for a new customer");
    it.todo("should calculate premium for a single amulet");
    it.todo("should calculate premium for a single component (rune)");
    it.todo("should apply block pricing for 3 alike components");
    it.todo("should add cursed item surcharge of 50%");
    it.todo("should add enchantment surcharge of 30% for enchantment level >= 5");
    it.todo("should apply loyalty discount of 20% for customers with >= 2 years");
    it.todo("should apply 15% subsequent contract discount on non-first policies");
    it.todo("should sum premiums for multiple items in a single quote");
    it.todo("should round premium amounts in MHPCO's favor");
  });

  describe("Claims", () => {
    it.todo("should apply 100G deductible to claim payout");
    it.todo("should fully reimburse damage to dragon material items");
    it.todo("should reimburse at 50% for items with enchantment level >= 8");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should track remaining cap across multiple claims on same policy");
  });
});

