const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

export function processScenario(input: unknown): unknown {
  const scenario = input as { customer: { yearsWithMHPCO: number }; steps: Array<{ op: string; items?: Array<{ type: string }> }> };
  const results = scenario.steps.map((step) => {
    const basePremium = BASE_PREMIUMS[step.items![0].type];
    const premium = Math.ceil(basePremium * 1.1) + 5;
    return { premium };
  });
  return { results };
}

