interface Item {
  type: string;
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Array<{ op: string; items?: Item[] }>;
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  rune: 25,
};

export function processScenario(input: unknown): unknown {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => {
    const basePremium = BASE_PREMIUMS[step.items![0].type];
    const premium = Math.ceil(basePremium * 11 / 10) + 5;
    return { premium };
  });
  return { results };
}

