export function processScenario(input: unknown): unknown {
  const scenario = input as Scenario;
  const FIRST_INSURANCE_SURCHARGE = 10;
  const SUBSEQUENT_DISCOUNT = -15;
  const LOYALTY_DISCOUNT = -20;
  const policies: Array<{ items: Item[] }> = [];
  let quoteIndex = 0;
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const basePremium = computeTotalBasePremium(step.items!);
      const contractModifier = quoteIndex === 0 ? FIRST_INSURANCE_SURCHARGE : SUBSEQUENT_DISCOUNT;
      quoteIndex++;
      const customerModifier = 100
        + contractModifier
        + (scenario.customer.yearsWithMHPCO >= 2 ? LOYALTY_DISCOUNT : 0);
      const premium = Math.ceil(basePremium * customerModifier / 100) + 5;
      policies.push({ items: step.items! });
      return { premium };
    } else {
      const policy = policies[step.policy!];
      let insuranceSum = 0;
      for (const item of policy.items) {
        insuranceSum += INSURANCE_VALUES[item.type];
      }
      const cap = insuranceSum * 2;
      let totalDamage = 0;
      for (const damage of step.incident!.damages) {
        totalDamage += damage.amount;
      }
      const payout = Math.max(0, totalDamage - DEDUCTIBLE);
      const remainingCap = cap - payout;
      return { payout, remainingCap };
    }
  });
  return { results };
}

